/**
 * Notification model — core types for the notification system.
 *
 * Architecture: Event-driven via EventBus.
 * - Services emit domain events (e.g., order:created)
 * - NotificationService subscribes to these events
 * - NotificationService dispatches to registered NotificationAdapters
 * - Each adapter handles one delivery channel (email, webhook, SMS, etc.)
 */

/**
 * Supported notification channels. Each channel has a corresponding adapter.
 */
export type NotificationChannel = 'email' | 'webhook' | 'sms' | 'in-app';

/**
 * Notification priority levels.
 */
export type NotificationPriority = 'low' | 'normal' | 'high' | 'urgent';

/**
 * The type/category of a notification, used for routing and preference filtering.
 */
export type NotificationType =
  | 'order-confirmation'
  | 'order-status-update'
  | 'user-welcome'
  | 'user-profile-update';

/**
 * Payload passed to notification adapters for delivery.
 * This is the channel-agnostic representation of a notification.
 */
export interface NotificationPayload {
  /** Unique notification ID */
  id: string;
  /** What kind of notification this is */
  type: NotificationType;
  /** Delivery channel */
  channel: NotificationChannel;
  /** Recipient identifier (email address, user ID, webhook URL, etc.) */
  recipient: string;
  /** Notification subject / title */
  subject: string;
  /** Notification body content */
  body: string;
  /** Priority level */
  priority: NotificationPriority;
  /** When the notification was created */
  createdAt: Date;
  /** Optional metadata for adapter-specific needs */
  metadata?: Record<string, unknown>;
}

/**
 * Result returned by an adapter after attempting delivery.
 */
export interface NotificationResult {
  /** Whether delivery succeeded */
  success: boolean;
  /** The notification that was sent */
  notificationId: string;
  /** The channel that handled delivery */
  channel: NotificationChannel;
  /** Error message if delivery failed */
  error?: string;
  /** Timestamp of delivery attempt */
  deliveredAt: Date;
}

/**
 * Stored notification record combining payload and delivery results.
 */
export interface NotificationRecord {
  payload: NotificationPayload;
  results: NotificationResult[];
}

/**
 * NotificationAdapter interface — the contract all delivery channel adapters must implement.
 *
 * Constraint: Every notification delivery channel (email, webhook, SMS, in-app)
 * must implement this interface and be registered with the NotificationService.
 *
 * Adapters are responsible for:
 * 1. Delivering the notification via their specific channel
 * 2. Returning a NotificationResult indicating success or failure
 * 3. Handling their own retries and error management internally
 *
 * Adapters must NOT:
 * - Emit events on the EventBus (that's the NotificationService's job)
 * - Access other adapters or services directly
 * - Modify the NotificationPayload they receive
 */

import type { NotificationChannel, NotificationPayload, NotificationResult } from '../models/notification.js';

export interface NotificationAdapter {
  /** The channel this adapter handles */
  readonly channel: NotificationChannel;

  /**
   * Send a notification through this adapter's channel.
   * Must not throw — return a failed NotificationResult instead.
   */
  send(payload: NotificationPayload): Promise<NotificationResult>;
}

/**
 * Email notification adapter — delivers notifications via email.
 *
 * This is a stub implementation that logs email sends in-memory.
 * A real implementation would use an SMTP client, SendGrid, SES, etc.
 *
 * Implements NotificationAdapter interface per the event-driven notification
 * architecture. Registered with NotificationService at startup.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface EmailMessage {
  to: string;
  subject: string;
  body: string;
  sentAt: Date;
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private sentEmails: EmailMessage[] = [];

  async send(payload: NotificationPayload): Promise<NotificationResult> {
    this.logger.info(`Sending email to ${payload.recipient}: ${payload.subject}`);

    const email: EmailMessage = {
      to: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      sentAt: new Date(),
    };

    this.sentEmails.push(email);

    return {
      success: true,
      notificationId: payload.id,
      channel: 'email',
      deliveredAt: email.sentAt,
    };
  }

  /**
   * Get all sent emails. Useful for testing.
   */
  getSentEmails(): EmailMessage[] {
    return [...this.sentEmails];
  }

  /**
   * Clear sent emails. Useful for testing.
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

/**
 * Notification service — dispatches notifications in response to domain events.
 *
 * Architecture: Event-driven via EventBus (exclusively).
 * - Subscribes to domain events on the EventBus
 * - Maps events to NotificationPayloads
 * - Dispatches payloads to registered NotificationAdapters
 *
 * Constraints:
 * - All notifications flow through EventBus.emit() — no direct service calls
 * - All delivery channels implement the NotificationAdapter interface
 * - Adapters are registered at construction time via registerAdapter()
 * - This service does NOT use CallbackRegistry
 *
 * Depends on:
 * - EventBus for receiving domain events
 * - NotificationAdapter implementations for delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent, UserCreatedEvent } from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  NotificationChannel,
  NotificationPayload,
  NotificationRecord,
  NotificationResult,
  NotificationType,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();
  private records: NotificationRecord[] = [];

  constructor(private eventBus: EventBus) {
    this.subscribeToEvents();
  }

  /**
   * Register a notification adapter for a delivery channel.
   * Only one adapter per channel is allowed — later registrations replace earlier ones.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registered adapter for channel: ${adapter.channel}`);
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Subscribe to all domain events that should trigger notifications.
   * All event handling goes through the EventBus — no other mechanism.
   */
  private subscribeToEvents(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) =>
      this.handleOrderCreated(event),
    );

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) =>
      this.handleOrderStatusChanged(event),
    );

    this.eventBus.on<UserCreatedEvent>('user:created', (event) =>
      this.handleUserCreated(event),
    );
  }

  /**
   * Handle order created — send confirmation notification.
   */
  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    await this.dispatch({
      type: 'order-confirmation',
      channel: 'email',
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      priority: 'normal',
    });
  }

  /**
   * Handle order status change — notify user of update.
   */
  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    await this.dispatch({
      type: 'order-status-update',
      channel: 'email',
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      priority: 'normal',
    });
  }

  /**
   * Handle user created — send welcome notification.
   */
  private async handleUserCreated(event: UserCreatedEvent): Promise<void> {
    await this.dispatch({
      type: 'user-welcome',
      channel: 'email',
      recipient: event.user.email,
      subject: 'Welcome to TaskFlow Pro!',
      body: `Hi ${event.user.name}, welcome to TaskFlow Pro. Your account has been created.`,
      priority: 'normal',
    });
  }

  /**
   * Dispatch a notification through the appropriate adapter.
   * This is the single point through which all notifications are sent.
   */
  private async dispatch(params: {
    type: NotificationType;
    channel: NotificationChannel;
    recipient: string;
    subject: string;
    body: string;
    priority: NotificationPayload['priority'];
    metadata?: Record<string, unknown>;
  }): Promise<NotificationResult> {
    const payload: NotificationPayload = {
      id: generateNotificationId(),
      type: params.type,
      channel: params.channel,
      recipient: params.recipient,
      subject: params.subject,
      body: params.body,
      priority: params.priority,
      createdAt: new Date(),
      metadata: params.metadata,
    };

    const adapter = this.adapters.get(params.channel);

    if (!adapter) {
      this.logger.warn(`No adapter registered for channel: ${params.channel}`);
      const failedResult: NotificationResult = {
        success: false,
        notificationId: payload.id,
        channel: params.channel,
        error: `No adapter registered for channel: ${params.channel}`,
        deliveredAt: new Date(),
      };
      this.records.push({ payload, results: [failedResult] });
      return failedResult;
    }

    const result = await adapter.send(payload);
    this.records.push({ payload, results: [result] });
    this.logger.info(
      `Notification ${payload.id} via ${params.channel}: ${result.success ? 'delivered' : 'failed'}`,
    );
    return result;
  }

  /**
   * Get all notification records.
   */
  getNotifications(): NotificationRecord[] {
    return [...this.records];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): NotificationRecord[] {
    return this.records.filter((r) => r.payload.recipient === recipient);
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.records.length;
  }

  /**
   * Clear all notification records (useful for testing).
   */
  clearNotifications(): void {
    this.records = [];
  }
}

